1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	const quoteResult = (premium: number) => ({ results: [{ premium }] });
11	
12	const firstInsuranceSurcharge = (base: number): number =>
13	  Math.ceil(base * FIRST_INSURANCE_SURCHARGE_RATE);
14	
15	const itemPremium = (item: { type: string }): number => {
16	  const base = BASE_PREMIUMS[item.type];
17	  return base + firstInsuranceSurcharge(base);
18	};
19	
20	export const runScenario = (input: any): unknown => {
21	  const items = input.steps[0].items;
22	  const itemsTotal = items.reduce(
23	    (sum: number, item: { type: string }) => sum + itemPremium(item),
24	    0,
25	  );
26	  return quoteResult(itemsTotal + PROCESSING_FEE);
27	};
